import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Trash2 } from 'lucide-react';
import '../styles/Katalog.css';

const Keranjang = ({ keranjang, setKeranjang, isLoggedIn }) => { // Tambahkan parameter isLoggedIn
  const [barangDipilih, setBarangDipilih] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    setBarangDipilih(keranjang.map(item => item.id));
  }, [keranjang]);

  const aturPilihBarang = (id) => {
    if (barangDipilih.includes(id)) {
      setBarangDipilih(barangDipilih.filter(itemId => itemId !== id));
    } else {
      setBarangDipilih([...barangDipilih, id]);
    }
  };

  const itemTerpilih = keranjang.filter(item => barangDipilih.includes(item.id));
  const totalJumlahBarang = itemTerpilih.reduce((total, item) => total + item.jumlah, 0);
  const totalHargaBelanja = itemTerpilih.reduce((total, item) => {
    const hargaAngka = parseInt(item.harga.replace(/[^0-9]/g, ''));
    return total + (hargaAngka * item.jumlah);
  }, 0);

  const handleCheckoutAction = () => {
    if (!isLoggedIn) {
      navigate('/login');
    } else {
      const nomorAdmin = "6281234567890";
      let pesan = "Halo Admin CampBread, saya ingin memesan:\n\n";
      itemTerpilih.forEach((item, index) => {
        pesan += `${index + 1}. ${item.nama} (${item.jumlah}x)${item.catatan ? ` - Catatan: ${item.catatan}` : ''}\n`;
      });
      pesan += `\n*Total: Rp ${totalHargaBelanja.toLocaleString('id-ID')}*`;
      window.open(`https://wa.me/${nomorAdmin}?text=${encodeURIComponent(pesan)}`, '_blank');
    }
  };

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      <div className="katalog-content" style={{ display: 'flex', gap: '30px', alignItems: 'flex-start' }}>
        <div style={{ flex: '2', background: 'white', borderRadius: '8px', border: '2px solid #38bdf8', overflow: 'hidden' }}>
          <div style={{ padding: '15px 20px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between' }}>
            <span>Keranjang Belanja</span>
            <span onClick={() => setKeranjang([])} style={{ color: '#ef4444', fontSize: '14px', fontWeight: 'bold', cursor: 'pointer' }}>Hapus Semua</span>
          </div>
          <div style={{ padding: '0 20px' }}>
            {keranjang.map(item => (
              <div key={item.id} style={{ display: 'flex', alignItems: 'center', padding: '20px 0', borderBottom: '1px solid #eee', gap: '15px' }}>
                <input type="checkbox" checked={barangDipilih.includes(item.id)} onChange={() => aturPilihBarang(item.id)} />
                <img src={item.img} alt={item.nama} style={{ width: '90px', height: '90px', borderRadius: '8px', objectFit: 'cover' }} />
                <div style={{ flex: '1' }}>
                  <h4 style={{ margin: 0 }}>{item.nama}</h4>
                  <p style={{ margin: '5px 0', color: '#666' }}>{item.harga}</p>
                  <input 
                    type="text" placeholder="Catatan" value={item.catatan || ''}
                    onChange={(e) => setKeranjang(keranjang.map(i => i.id === item.id ? {...i, catatan: e.target.value} : i))}
                    style={{ width: '100%', padding: '8px', background: '#e5e7eb', border: 'none', borderRadius: '4px', fontSize: '12px' }}
                  />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '10px' }}>
                  <span style={{ fontWeight: 'bold' }}>{item.jumlah}x</span>
                  <Trash2 size={20} color="#ef4444" style={{ cursor: 'pointer' }} onClick={() => setKeranjang(keranjang.filter(i => i.id !== item.id))} />
                </div>
              </div>
            ))}
          </div>
        </div>
        <div style={{ flex: '1', background: 'white', borderRadius: '8px', padding: '25px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
          <h3 style={{ margin: '0 0 20px 0', fontSize: '16px' }}>Ringkasan Belanja</h3>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px', color: '#666' }}>
            <span>Total Harga ({totalJumlahBarang} Barang)</span>
            <span>Rp {totalHargaBelanja.toLocaleString('id-ID')}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px', fontWeight: 'bold' }}>
            <span>Total Belanja</span>
            <span>Rp {totalHargaBelanja.toLocaleString('id-ID')}</span>
          </div>
          <button onClick={handleCheckoutAction} style={{ width: '100%', padding: '14px', background: '#b45309', color: 'white', border: 'none', borderRadius: '6px', fontWeight: 'bold', cursor: 'pointer' }}>
            {isLoggedIn ? "Konfirmasi Pesanan" : "Login untuk Checkout"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Keranjang;
